/// <remarks>
/// NotebookException follows a two-tier pattern based on whether ErrorCode is set:
///
/// 1. ErrorCode IS set ... The Message property contains a fully formatted, user-facing error string that can be surfaced directly — no further wrapping needed.
///
/// 2. ErrorCode is NULL ... The Message is a raw/technical string ... that must be wrapped inside the MLV_LINEAGE_CREATION_NOTEBOOK_EXCEPTION template ...
///
/// Downstream consumers ... branch on ErrorCode.HasValue to decide which path to take. This is intentional — do not replace with a Message null/empty check, because both tiers always carry a Message.
/// </remarks>
public ErrorCode? ErrorCode { get; }

