private ProblemDetails CreateProblemDetails(HttpStatusCode statusCode, string title, string detail)
{
    return new ProblemDetails
    {
        Status = (int)statusCode,
        Title = title,
        Detail = detail,
        Instance = this.HttpContext.Request.Path,
    };
}
